INSERT INTO `Product` VALUES (17,'Каравана -TRACER25BHS','prime-time','Каравана PRIME TIME модел TRACER25BHS нова и напълно оборудвана\nДължина 9 м и капацитет 6 места за спане\nСтените и таванът са изцяло алуминиева двойно заварена конструкция с изолация от полистирен\nВъншното и вътрешното покритие е от фибростъкло\nКараваната разполага със слайд в дневната част за повече пространство\nОборудвана е с електрически крик за теглича\nРазполага с хладилник 300 л на 12V\nОборудвана е с канален климатик 14500 BTU\nИма газов и електрически бойлер 24 л\nОтоплението е газово с мощност 30000 BTU\nРазполага с газова фурна с три котлона и абсорбатор\nОборудвана е с микровълнова фурна\nРазполага с телевизор 40 инча\nИма електрически крикове за стабилизация\nОборудвана е с WIFI антена за телевизия и интернет 4G\nРазполага със саундбар с висока разделителна способност\nИма електрическа тента с дължина 5.7 м\nКараваната разполага със съд за чиста вода 170 л\nОборудвана е със съд за отпадна вода 250 л\nРазполага със съд за тоалетната 120 л',6000000,1,'2026-02-02 17:29:05.444','2026-02-02 17:32:53.450',4,7),(11,'P.L.A Мистер 570 – 5 места','kemper-pod-naem-5-mesta','Кемпер под наем, напълно оборудван и подходящ за до 5 човека. Идеален за дълги пътувания и къмпинг приключения\nКемперът разполага с телевизор с дистанционно управление и хладилник Thetford\nОборудван е с инвертор и соларна система\nИма климатик в караванната част, както и климатик към двигателя\nРазполага с бойлер, печка, котлони и газови бутилки\nОборудван е с тоалетна касета и вътрешна стълба\nЗа удобство има CD радио, TV антена и тента Fiamma с манивела\nВключени са триъгълник, крик, пожарогасител и аптечка за безопасност по време на пътуване\nКемперът предлага 5 спални места и 5 седалки\nAutoline ID: СТ 8993\nЦената за наем намалява при по-дълъг период на ползване\nПри наем от 2 до 7 дни цената е 270 лв на ден\nПри наем от 8 до 14 дни цената е 255 лв на ден\nПри наем от 15 до 21 дни цената е 240 лв на ден\nПри наем 